#include <iostream>
#include <vector>
using namespace std;

// Binary search function
int binarySearch(vector<int> &arr, int lo, int hi, int x) {
    while (lo <= hi) {
        int mid = lo + (hi - lo) / 2;
        if (arr[mid] == x) return mid;
        if (arr[mid] < x) lo = mid + 1;
        else hi = mid - 1;
    }
    return -1;
}

// Function to find pivot (index of the smallest element)
int findPivot(vector<int> &arr, int lo, int hi) {
    while (lo < hi) {
        if (arr[lo] <= arr[hi]) return lo;
        int mid = (lo + hi) / 2;
        if (arr[mid] > arr[hi]) lo = mid + 1;
        else hi = mid;
    }
    return lo;
}

// Function to search for the key in the rotated sorted array
int search(vector<int> &arr, int key) {
    int n = arr.size();
    int pivot = findPivot(arr, 0, n - 1);

    if (arr[pivot] == key) return pivot;
    if (pivot == 0) return binarySearch(arr, 0, n - 1, key);
    if (arr[0] <= key) return binarySearch(arr, 0, pivot - 1, key);
    return binarySearch(arr, pivot, n - 1, key);
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int N, K;
        cin >> N >> K;
        vector<int> arr(N);
        for (int i = 0; i < N; i++) cin >> arr[i];
        cout << search(arr, K) << endl;
    }
    return 0;
}

