#include <stdio.h>

int search(int A[], int N, int K) {
    int low = 0, high = N - 1;

    while (low <= high) {
        int mid = low + (high - low) / 2;

        if (A[mid] == K) return mid;

        // Left half is sorted
        if (A[low] <= A[mid]) {
            if (K >= A[low] && K < A[mid]) {
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        } 
        // Right half is sorted
        else {
            if (K > A[mid] && K <= A[high]) {
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
    }
    return -1;
}

int main() {
    int T;
    // Check if input is successfully read
    if (scanf("%d", &T) != 1) return 0;

    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);

        int A[5005]; // Max N is 5000 based on constraints
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }

        printf("%d\n", search(A, N, K));
    }

    return 0;
}

