import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        if (!sc.hasNextInt()) return;

        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();

            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }

            System.out.println(search(A, N, K));
        }
        sc.close();
    }

    private static int search(int[] A, int N, int K) {
        int low = 0, high = N - 1;

        while (low <= high) {
            int mid = low + (high - low) / 2;

            if (A[mid] == K) {
                return mid;
            }

            // Check if the left half is sorted
            if (A[low] <= A[mid]) {
                // Check if K is within the left sorted half
                if (K >= A[low] && K < A[mid]) {
                    high = mid - 1;
                } else {
                    low = mid + 1;
                }
            } 
            // Otherwise, the right half must be sorted
            else {
                // Check if K is within the right sorted half
                if (K > A[mid] && K <= A[high]) {
                    low = mid + 1;
                } else {
                    high = mid - 1;
                }
            }
        }
        return -1; // K not found
    }
}
